files.content:
h1 {
  text-align: center;
  margin-bottom: 10px;
}

.box {
  max-height: 120px;
  color: #000;
  border: 1px solid #000;
  display: flex;
  flex: 0 0 150px;
  flex-direction: column;
  align-items: center;
  margin: 10px;
  font-weight: bold;
  font-size: 1.125rem;
  border-radius: 5px;
  order: 0;
}

.flex-container {
  display: flex;
  flex-wrap: wrap;
  width: 70%;
  height: 600px;
  padding: 10px;
  margin: 20px auto;
  align-content: space-evenly;
}

.box1 { background: #f16e79; order: 1; flex-grow: 1; }
.box2 { background: #f4a261; order: 0; }
.box3 { background: #ffd166; order: 2; flex-shrink: 3; }
.box4 { background: #4caf50; order: 3; }
.box5 { background: #457b9d; order: 4; }
.box6 { background: #3f51b5; order: 5; flex-grow: 1; }
